const payload = $json || {};
const notionUrls = Array.isArray(payload.notion_urls)
  ? payload.notion_urls
  : (payload.notion_url ? [payload.notion_url] : []);
const githubUrls = Array.isArray(payload.github_urls)
  ? payload.github_urls
  : (payload.github_url ? [payload.github_url] : []);

const maxSources = Math.min(Math.max(Number(payload.max_sources || 4), 1), 5);
const deduped = [];
const seen = new Set();

for (const raw of [...notionUrls, ...githubUrls]) {
  const url = String(raw || '').trim();
  if (!url) continue;
  if (!/^https?:\/\//i.test(url)) continue;
  const key = url.toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  deduped.push(url);
}

if (deduped.length === 0) {
  deduped.push('https://github.com/issdandavis/SCBE-AETHERMOORE/tree/main/docs');
}

const selected = deduped.slice(0, maxSources);
const actions = [];
for (const url of selected) {
  actions.push({ action: 'navigate', target: url, timeout_ms: 15000 });
  actions.push({ action: 'extract', target: 'body', timeout_ms: 12000 });
  if (actions.length >= 10) break;
}

const runId = payload.run_id || `notion-gh-${Date.now()}`;
const sessionId = payload.session_id || `swarm-${Date.now()}`;
const query = String(payload.query || '');

return [{
  json: {
    workflow_id: 'n8n-notion-github-swarm',
    run_id: runId,
    session_id: sessionId,
    source: 'n8n',
    dry_run: !!payload.dry_run,
    actions,
    query,
    source_manifest: {
      notion_urls: notionUrls,
      github_urls: githubUrls,
      selected_urls: selected
    }
  }
}];

const result = $json || {};
const rows = Array.isArray(result.results) ? result.results : [];
const snippets = [];
for (const row of rows) {
  if (row && row.data && typeof row.data.extracted_text === 'string') {
    snippets.push(row.data.extracted_text.slice(0, 280));
  }
  if (snippets.length >= 4) break;
}

const summary = [
  `run=${result.integration?.run_id || result.session_id || 'unknown'}`,
  `status=${result.status || 'unknown'}`,
  `executed=${result.executed_actions ?? 0}/${result.total_actions ?? 0}`,
  `blocked=${result.blocked_actions ?? 0}`,
  `trace=${result.trace || ''}`,
  snippets.length ? `snippets=${snippets.join(' | ')}` : 'snippets=none'
].join(' ; ');

return [{
  json: {
    summary,
    run_id: result.integration?.run_id || result.session_id || `notion-gh-${Date.now()}`,
    status: result.status || 'unknown',
    trace: result.trace || '',
    raw_result: result
  }
}];
